#!/usr/bin/env bash
###############################################################################
# halow-offline-install.sh  -  SELF-CONTAINED MM6108 HaLow driver installer
#
#   * Carries the PATCHED morse_driver 1.17.9 source + firmware INSIDE itself.
#   * No internet / no GitHub needed at run time.
#   * Generic & network-agnostic: reusable on any STOCK-KERNEL Raspberry Pi 5
#     with a Seeed WM1302 + Wio-WM6108 (Morse Micro MM6108) SPI HaLow HAT.
#
#   *** THE KERNEL IS NEVER MODIFIED. ***
#   No kernel is patched, rebuilt, or replaced. The two source patches are to
#   the Morse DRIVER's own files (its Makefile and spi.c) - an out-of-tree
#   module. morse.ko/dot11ah.ko are compiled AGAINST the stock kernel's headers
#   in the normal out-of-tree way and dropped in /lib/modules/.../updates/.
#   The device-tree OVERLAY is an add-on (dtoverlay=), not a change to the base
#   kernel or its DTB. The stock kernel stays byte-for-byte untouched.
#
# IMAGE PREREQS (bake into the image so it runs fully offline):
#   build-essential dkms bc device-tree-compiler
#   raspberrypi-kernel-headers   <- kernel HEADERS only, to COMPILE the module
#                                   against the stock kernel. Does NOT modify it.
#   raspberrypi-utils            <- provides pinctrl
#
# USAGE:  sudo ./halow-offline-install.sh    then    sudo reboot
###############################################################################
set -uo pipefail
SELF="$(readlink -f "$0")"
[ "$(id -u)" -ne 0 ] && exec sudo -E bash "$SELF" "$@"

LOG=/var/log/halow-offline-install.log
exec > >(tee -a "$LOG") 2>&1
echo "=== halow-offline-install start $(date) ==="

DRIVER_TAG="1.17.9"
FW=/lib/firmware/morse
KREL="$(uname -r)"
KBUILD="/lib/modules/$KREL/build"
FLAGS="CONFIG_WLAN_VENDOR_MORSE=m CONFIG_MORSE_SDIO=y CONFIG_MORSE_SPI=y CONFIG_MORSE_USER_ACCESS=y CONFIG_MORSE_VENDOR_COMMAND=y CONFIG_MORSE_DEBUGFS=y"
PC="$(command -v pinctrl || true)"
# Board Config File for the Seeed WM6108 / Quectel FGH100M-H module.
# Override for other modules via:  sudo PD_BCF=bcf_xxx.bin ./halow-offline-install.sh
BCF="${PD_BCF:-bcf_fgh100mhaamd.bin}"

# ---- 0. extract embedded payload (patched source + firmware) ----
TMP="$(mktemp -d)"
trap 'rm -rf "$TMP"' EXIT
START="$(awk '/^__PD_PAYLOAD_BELOW__$/{print NR+1; exit}' "$SELF")"
[ -n "$START" ] || { echo "FATAL no payload marker"; exit 1; }
echo "[*] extracting embedded source + firmware"
tail -n +"$START" "$SELF" | base64 -d | tar xzf - -C "$TMP" || { echo "FATAL payload extract"; exit 1; }
SRC="$TMP/src"
[ -f "$SRC/Makefile" ] && [ -f "$SRC/spi.c" ] || { echo "FATAL payload incomplete"; exit 1; }

# ---- 1. build tools (offline-first; resilient apt fallback if reachable) ----
# On a properly prepared image these are already present and NO apt runs.
# If missing and the Pi has internet, each package is installed INDIVIDUALLY
# with retries so one unavailable package or a transient mirror error can never
# abort the whole batch (the bug that bit the first cut of this script).
need_tools() { command -v dkms >/dev/null && command -v dtc >/dev/null && command -v make >/dev/null && [ -n "$PC" ] && [ -d "$KBUILD" ]; }
apt_try() { # install ONE package resiliently; never aborts the script
  local pkg="$1" n=0
  while [ "$n" -lt 4 ]; do
    apt-get install -y --fix-missing "$pkg" >/dev/null 2>&1 && return 0
    n=$((n+1)); sleep 4; apt-get update -y >/dev/null 2>&1 || true
  done
  return 1
}
if ! need_tools; then
  echo "[*] build tools missing - attempting apt (image should prebake these for true offline)"
  export DEBIAN_FRONTEND=noninteractive
  apt-get update -y >/dev/null 2>&1 || true
  for pkg in dkms build-essential bc device-tree-compiler; do
    command -v "${pkg%% *}" >/dev/null 2>&1 || apt_try "$pkg" || echo "[warn] apt could not get $pkg (mirror issue? prebake it in the image)"
  done
  # kernel HEADERS (to compile against the stock kernel - does not modify it)
  if [ ! -d "$KBUILD" ]; then
    for pkg in raspberrypi-kernel-headers linux-headers-$KREL linux-headers-rpi-2712 linux-headers-rpi-v8; do
      apt_try "$pkg"; [ -d "$KBUILD" ] && break
    done
  fi
  # pinctrl: normally preinstalled on Pi images. Only chase a provider if absent.
  # NB: the package is 'raspi-utils' on Debian/Parrot (NOT 'raspberrypi-utils').
  if [ -z "$PC" ]; then
    for pkg in raspi-utils raspberrypi-utils; do apt_try "$pkg" && break; done
    PC="$(command -v pinctrl || true)"
  fi
fi
command -v dkms >/dev/null || { echo "FATAL: dkms not available (bake 'dkms' into the image)"; exit 1; }
command -v dtc  >/dev/null || { echo "FATAL: dtc not available (bake 'device-tree-compiler' into the image)"; exit 1; }
command -v make >/dev/null || { echo "FATAL: make not available (bake 'build-essential' into the image)"; exit 1; }
[ -n "$PC" ]               || { echo "FATAL: pinctrl not available (bake 'raspi-utils' into the image)"; exit 1; }
[ -d "$KBUILD" ]           || { echo "FATAL: kernel headers for $KREL not available (bake 'raspberrypi-kernel-headers')"; exit 1; }

# ---- 2. firmware ----
echo "[*] installing firmware"
install -d "$FW"
cp -Lf "$TMP"/firmware/*.bin "$FW/" || { echo "FATAL firmware copy"; exit 1; }
[ -f "$FW/mm6108.bin" ] || { echo "FATAL mm6108.bin missing"; exit 1; }
[ -f "$FW/$BCF" ] || { echo "FATAL board config $BCF missing from payload"; exit 1; }
echo "[*] using board config: $BCF"

# ---- 3. build (source is already patched) ----
echo "[*] building driver (already patched: no -Werror, manual SPI training)"
cd "$SRC"
make -s clean >/dev/null 2>&1 || true
make -s KERNEL_SRC="$KBUILD" $FLAGS || { echo "FATAL build"; exit 1; }
[ -f morse.ko ] && [ -f dot11ah/dot11ah.ko ] || { echo "FATAL no .ko produced"; exit 1; }

echo "[*] installing modules"
install -d "/lib/modules/$KREL/updates"
install -m644 morse.ko "/lib/modules/$KREL/updates/"
install -m644 dot11ah/dot11ah.ko "/lib/modules/$KREL/updates/"
depmod -a "$KREL"

# ---- 4. device-tree overlay (add-on, not a kernel change) ----
echo "[*] device-tree overlay"
cat > "$TMP/morse-spi.dts" <<DTS
/dts-v1/;
/plugin/;
/ { compatible = "brcm,bcm2712";
 fragment@0 { target = <&spi0>;
  __overlay__ { status="okay"; #address-cells=<1>; #size-cells=<0>;
   cs-gpios = <&gpio 8 1>;
   morse@0 { compatible="morse,mm610x-spi"; reg=<0>; spi-max-frequency=<10000000>;
    reset-gpios=<&gpio 17 0>; power-gpios=<&gpio 23 0>,<&gpio 24 0>;
    spi-irq-gpios=<&gpio 5 0>; status="okay"; }; }; }; };
DTS
if [ -d /boot/firmware/overlays ]; then OVR=/boot/firmware/overlays; CFG=/boot/firmware/config.txt
else OVR=/boot/overlays; CFG=/boot/config.txt; fi
dtc -@ -I dts -O dtb -o "$OVR/morse-spi.dtbo" "$TMP/morse-spi.dts" 2>/dev/null || { echo "FATAL dtc compile"; exit 1; }
cp -n "$CFG" "$CFG.pdbak" 2>/dev/null || true
for L in "dtparam=spi=on" "dtoverlay=spi0-0cs" "dtoverlay=morse-spi"; do
  grep -qxF "$L" "$CFG" || echo "$L" >> "$CFG"
done
echo "blacklist morse" > /etc/modprobe.d/morse.conf

# ---- 5. boot bring-up service (manual SPI training burst) ----
echo "[*] boot service"
cat > /usr/local/bin/start_morse.sh <<MS
#!/usr/bin/env bash
PC="$PC"
\$PC set 17 op dl; sleep 0.05; \$PC set 17 ip pu; sleep 0.10
\$PC set 8 op dh; \$PC set 10 op dh; \$PC set 11 op dl
for i in \$(seq 1 80); do \$PC set 11 dh; \$PC set 11 dl; done
\$PC set 8 a0; \$PC set 9 a0; \$PC set 10 a0; \$PC set 11 a0
modprobe morse bcf=$BCF; sleep 3
MS
chmod +x /usr/local/bin/start_morse.sh
cat > /etc/systemd/system/start_morse.service <<SVC
[Unit]
Description=PurpleDeck HaLow bring-up
After=multi-user.target
[Service]
Type=oneshot
RemainAfterExit=yes
ExecStart=/usr/local/bin/start_morse.sh
[Install]
WantedBy=multi-user.target
SVC
systemctl daemon-reload
systemctl enable start_morse.service >/dev/null 2>&1

# ---- 6. DKMS - survive kernel updates (hardened + verified) ----
echo "[*] dkms register"
# ensure the kernel-HEADERS meta-package is present so a FUTURE kernel update
# has headers to rebuild against (best-effort; does not modify the kernel).
apt-get install -y raspberrypi-kernel-headers >/dev/null 2>&1 || true
DK="/usr/src/morse-driver-$DRIVER_TAG"
rm -rf "$DK"; mkdir -p "$DK"; cp -a "$SRC/." "$DK/"; rm -rf "$DK/.git"
cat > "$DK/dkms.conf" <<DKMS
PACKAGE_NAME="morse-driver"
PACKAGE_VERSION="$DRIVER_TAG"
CLEAN="make -s clean"
MAKE[0]="make -s KERNEL_SRC=\${kernel_source_dir} $FLAGS"
BUILT_MODULE_NAME[0]="morse"
BUILT_MODULE_LOCATION[0]="."
DEST_MODULE_LOCATION[0]="/updates"
BUILT_MODULE_NAME[1]="dot11ah"
BUILT_MODULE_LOCATION[1]="dot11ah"
DEST_MODULE_LOCATION[1]="/updates"
AUTOINSTALL="yes"
DKMS
dkms remove -m morse-driver -v "$DRIVER_TAG" --all >/dev/null 2>&1 || true
dkms add -m morse-driver -v "$DRIVER_TAG" >/dev/null 2>&1 || true
dkms build -m morse-driver -v "$DRIVER_TAG" -k "$KREL" >/dev/null 2>&1 || true
dkms install --force -m morse-driver -v "$DRIVER_TAG" -k "$KREL" >/dev/null 2>&1 || true
# explicit verification that DKMS is actually registered for this kernel:
if dkms status -m morse-driver -v "$DRIVER_TAG" 2>/dev/null | grep -q "$KREL"; then
  echo "[ok] DKMS registered AND verified for kernel $KREL"
  if [ -d "/usr/src/linux-headers-$KREL" ] || [ -d "$KBUILD" ]; then
    echo "[ok] auto-rebuild-on-kernel-update: ARMED (AUTOINSTALL=yes, headers present)"
  else
    echo "[warn] DKMS armed but no headers staged - future kernel may need headers installed before HaLow rebuilds"
  fi
else
  echo "[warn] DKMS NOT verified - module is installed manually for $KREL but will NOT auto-rebuild on a kernel update"
fi

echo "=== HALOW-INSTALL-DONE $(date) ==="
echo
echo "Reboot to bring up HaLow:  sudo reboot"
echo "After reboot verify:       dmesg | grep -iE 'morse|chip' ; ip -br link | grep -i wlan"
echo "DKMS status:               dkms status | grep morse"
exit 0
__PD_PAYLOAD_BELOW__

